class ApiLoggingInterceptor(
    private val redactHeaders: Set<String> = setOf("Authorization", "Cookie", "Set-Cookie", "X-Api-Key"),
    private val maxBodyBytes: Long = 1024L * 1024L,
    private val logRequestBody: Boolean = true,
    private val logResponseBody: Boolean = true,
    private val includeTiming: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val requestId = UUID.randomUUID().toString()
        val request = chain.request()

        val startNs = System.nanoTime()
        logRequest(requestId, request)

        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            AppLogger.logException(t, "API call failed id=%s method=%s url=%s", requestId, request.method, request.url.toString())
            throw t
        }

        val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
        logResponse(requestId, request, response, tookMs)

        return response
    }

    private fun logRequest(id: String, request: Request) {
        val url = request.url.toString()
        val method = request.method
        val headers = request.headers.redacted(redactHeaders)

        val bodyInfo = if (logRequestBody) request.body.safeBodyString(maxBodyBytes) else "<omitted>"
        AppLogger.v(
            "API request id=%s method=%s url=%s\nheaders=%s\nbody=%s",
            id, method, url, headers.toMultilineString(), bodyInfo
        )
    }

    private fun logResponse(id: String, request: Request, response: Response, tookMs: Long) {
        val code = response.code
        val message = response.message
        val url = request.url.toString()
        val headers = response.headers.redacted(redactHeaders)

        val timing = if (includeTiming) " tookMs=$tookMs" else ""
        if (!logResponseBody) {
            AppLogger.v(
                "API response id=%s code=%d message=%s url=%s%s\nheaders=%s\nbody=%s",
                id, code, message, url, timing, headers.toMultilineString(), "<omitted>"
            )
            return
        }

        val peeked = response.peekBody(maxBodyBytes)
        val bodyStr = peeked.safeString()
        AppLogger.v(
            "API response id=%s code=%d message=%s url=%s%s\nheaders=%s\nbody=%s",
            id, code, message, url, timing, headers.toMultilineString(), bodyStr
        )
    }

    private fun Headers.redacted(redact: Set<String>): Headers {
        if (size == 0) return this
        val builder = Headers.Builder()
        for (i in 0 until size) {
            val name = name(i)
            val value = value(i)
            if (redact.any { it.equals(name, ignoreCase = true) }) {
                builder.add(name, "██REDACTED██")
            } else {
                builder.add(name, value)
            }
        }
        return builder.build()
    }

    private fun Headers.toMultilineString(): String {
        if (size == 0) return "{}"
        val sb = StringBuilder("{\n")
        for (i in 0 until size) {
            sb.append("  ").append(name(i)).append(": ").append(value(i)).append('\n')
        }
        sb.append("}")
        return sb.toString()
    }

    private fun RequestBody?.safeBodyString(maxBytes: Long): String {
        if (this == null) return "null"
        return try {
            val buffer = Buffer()
            writeTo(buffer)
            val contentType = contentType()
            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            if (!buffer.isProbablyUtf8()) {
                "<binary body omitted; contentType=${contentType?.toString() ?: "unknown"} bytes=${buffer.size}>"
            } else {
                val limited = buffer.readByteString(minOf(buffer.size, maxBytes)).string(charset)
                val suffix = if (buffer.size > maxBytes) "…(truncated ${buffer.size - maxBytes} bytes)" else ""
                limited + suffix
            }
        } catch (t: Throwable) {
            "<failed to read request body: ${t::class.java.simpleName}: ${t.message}>"
        }
    }

    private fun ResponseBody.safeString(): String {
        return try {
            val contentType = contentType()
            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val source = source()
            source.request(Long.MAX_VALUE)
            val buffer = source.buffer.clone()

            val encoding = headers()["Content-Encoding"]
            val finalBuffer = if (encoding != null && encoding.equals("gzip", ignoreCase = true)) {
                val gz = GzipSource(buffer.clone())
                val out = Buffer()
                out.writeAll(gz)
                out
            } else buffer

            if (!finalBuffer.isProbablyUtf8()) {
                "<binary body omitted; contentType=${contentType?.toString() ?: "unknown"} bytes=${finalBuffer.size}>"
            } else {
                finalBuffer.readString(charset)
            }
        } catch (t: Throwable) {
            "<failed to read response body: ${t::class.java.simpleName}: ${t.message}>"
        }
    }

    private fun Buffer.isProbablyUtf8(): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = minOf(size, 64)
            copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) return false
            }
            true
        } catch (_: EOFException) {
            false
        } catch (_: Throwable) {
            false
        }
    }
}

object ExceptionLogging {

    @Volatile
    private var installed = false

    fun installGlobalHandler() {
        if (installed) return
        synchronized(this) {
            if (installed) return
            val previous = Thread.getDefaultUncaughtExceptionHandler()
            Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                try {
                    AppLogger.logException(
                        throwable,
                        "UNCAUGHT exception thread=%s id=%d name=%s sdk=%d device=%s model=%s",
                        thread.name,
                        thread.id,
                        thread.toString(),
                        Build.VERSION.SDK_INT,
                        Build.MANUFACTURER,
                        Build.MODEL
                    )
                } catch (_: Throwable) {
                } finally {
                    previous?.uncaughtException(thread, throwable)
                }
            }
            installed = true
        }
    }
}

