class DbLogger(private val dbName: String) {

    inline fun <T> measureQuery(sql: String, args: List<Any?>? = null, block: () -> T): T {
        val start = System.nanoTime()
        return try {
            val result = block()
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.dbQuery(dbName, sql, args, durationMs = tookMs)
            result
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.dbQuery(dbName, sql, args, durationMs = tookMs)
            AppLogger.logException(t, "DB exception db=%s sql=%s", dbName, sql)
            throw t
        }
    }

    inline fun <T> transaction(name: String, block: () -> T): T {
        val start = System.nanoTime()
        return try {
            val result = block()
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.dbTransaction(dbName, name, success = true, durationMs = tookMs)
            result
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.dbTransaction(dbName, name, success = false, durationMs = tookMs, error = t)
            throw t
        }
    }
}

